INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-5ff21eeb-moex-00012', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲、乙、丙、丁、戊5人互約出資以合夥開設A餐廳，約定合夥之決議，得由合夥人全體過半數 同意為之，並約定合夥之事務，由甲、乙、丙3人執行。嗣後，因A餐廳經營不善，甲、乙、丙 3人擬變更事業種類為經營B健身中心，惟丁、戊對此表示反對。下列敘述何者錯誤？', '["甲、乙、丙3人得以全體合夥人過半數同意之方式，決議變更事業種類為經營B健身中心", "甲就A餐廳之通常事務，得單獨執行之", "丁得隨時檢查A餐廳之事務及其財產狀況，並得查閱帳簿", "戊不必得甲、乙、丙、丁全體合夥人之同意，即可將自己之股份轉讓於丁"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00013', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲公司向乙借款若干，約定應於民國（下同）98年3月1日償還，甲之大股東丙，以及甲之董事 丁，均同意就上述借款為甲擔任連帶保證人，並拋棄先訴抗辯權。詎甲屆期無力償還借款，丁復 於113年2月5日卸任董事職務，乙遂於同年月20日向甲請求償還借款，甲旋向乙承認其所積 欠之借款。乙復於同年 4 月 15 日請求丙、丁連帶清償上述債務，丙提出乙基於連帶保證之請求 權已罹於消滅時效之抗辯，丁則以其並無職務在身為由，拒負保證之責。依實務見解，下列敘述 何者錯誤？', '["甲向乙承認借款債務，對丙亦生中斷時效之效力", "乙請求已卸任董事職務之丁，就甲之借款負連帶保證責任，並無理由", "丙抗辯乙之連帶保證請求權已罹於消滅時效，屬有理由", "甲向乙承認借款債務，發生中斷時效之效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00014', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲向乙購買A骨董花瓶，買賣價金為新臺幣（下同）100萬元，約定於民國（下同）113年5月 2日給付，並由丙擔任保證人。113年5月2日當天，甲並未給付價金。乙對甲之財產強制執行 後，因甲一貧如洗，乙無法受償，而請丙幫甲付100萬元。下列敘述何者錯誤？', '["若甲訂立買賣契約係因受乙之脅迫，依民法第 744 條有關保證人拒絕清償之規定，丙得拒絕 清償", "若甲對乙有10萬元之債權，丙得主張用該筆10萬元之債權抵銷", "丙代甲給付100萬元後，丙得向甲請求100萬元", "甲對債之發生原因之法律行為有撤銷權，但甲並未行使該撤銷權。由於該撤銷權不得由丙直接 主張，因此丙仍須向乙為清償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00015', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲、乙約定，甲於乙之受僱人丙，將來因職務上之行為而應對乙為損害賠償時，由甲代負賠償責 任。關於甲、乙間之人事保證契約，下列敘述何者錯誤？', '["若甲與乙僅以口頭約定人事保證契約，並約定期間為10年。則該人事保證約定期間，縮短為3 年，仍為有效", "除法律另有規定或契約另有訂定外，甲依人事保證契約應負賠償責任時，其賠償金額以賠償事 故發生時，丙當年可得報酬之總額為限", "若甲、乙間之人事保證未定期間者，自成立之日起有效期間為3年", "若甲、乙間之人事保證未定期間者，甲得隨時終止契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00016', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲之土地因受戊之土地所包圍，致無法與公路相通，嗣後，甲在其土地上興建A屋，並將該屋出 租於乙，乙則僱用員工丙利用A屋經營咖啡廳，須經常往返該公路，甲將其土地設定普通抵押權 於丁。下列何者對戊之土地，不得依民法第787條有關袋地通行權之規定，取得法定通行權？', '["甲", "乙", "丙", "丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00017', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲於自己所有之土地上建造房屋時，該建物之一部分逾越地界於乙所有之鄰地，下列敘述何者正 確？', '["無論甲為故意或過失，乙均得請求拆除越界之建物", "乙知情後即提出異議時，任何人均不得干涉乙請求拆除越界建物之主張", "如乙不請求甲拆除越界部分建築時，得請求甲價購遭越界部分之土地", "甲受乙之請求而拆除越界部分建物，即不必賠償因越界對乙所造成之損害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00018', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲對乙負有新臺幣 1,000 萬元借款債務。關於甲對乙所負該筆借款債務履行之擔保，下列敘述何 者錯誤？', '["甲得以自己之不動產，設定普通抵押權於乙", "第三人得以自己之不動產，設定普通抵押權於乙", "甲得與乙成立保證契約，以自己為保證人", "第三人得與乙成立保證契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00019', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲是A地所有人，出賣A地於乙。關於甲對乙所負A地所有權移轉義務之履行，下列敘述何者 錯誤？', '["甲與乙應成立A地所有權移轉契約", "甲應交付A地於乙", "甲應以書面為之", "甲與乙應至地政機關完成A地所有權移轉登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00020', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '關於典權之定義及效力規定，下列敘述何者正確？', '["稱典權者，謂以自己或他人之不動產不移轉占有而供債權擔保，於他人不回贖時，取得該不動 產所有權之權", "典權人於典權設定後，負支付典價之義務", "典權存續中，典權人不得將典物轉典於他人", "典權人對於典物因轉典所受之損害，負過失之賠償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00021', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列關於民法第876條法定地上權成立要件之敘述，何者錯誤？', '["土地所有人將其土地設定抵押權後，在抵押之土地上營造建築物", "設定抵押權時，土地及其土地上之建築物，同屬於1人所有", "所有人僅以土地或僅以建築物設定抵押，或以土地及建築物為抵押而其後拍定人各異", "抵押權人須以拍賣之方式而實行抵押權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL)
